      density: adjustedDensity * 0.15,
      relevance: relevance * 0.2,
      diversity: diversity * 0.15,
      energy: energy * 0.08,
      affinity: affinity * 0.14,
      signature: signature * 0.1,
      coherence: coherence * 0.04,
      sequenceSupport: sequenceSupport * 0.04,
